// Read all data from Webhook JSON fields.
// Laravel sends file_base64 and mime_type as plain text form fields,
// so we never need to touch n8n binary data (which is inaccessible in the Code node sandbox).
const webhook = $('Webhook').first().json.body;

return {
  base64: webhook.file_base64,
  mimeType: webhook.mime_type || 'application/octet-stream',
  requirement_text: webhook.requirement_text || '',
  evidence_file_id: webhook.evidence_file_id || '',
  project_name: webhook.project_name || '',
  requirement_num: webhook.requirement_num || '',
  original_filename: webhook.original_filename || '',
  auditor_email: webhook.auditor_email || '',
  review_link: webhook.review_link || '',
  gemini_api_key: webhook.gemini_api_key || ''
};

parameters.jsonBody:
={
  "contents": [
    {
      "parts": [
        {
          "inlineData": {
            "mimeType": "{{ $json.mimeType }}",
            "data": "{{ $json.base64 }}"
          }
        },
        {
          "text": "You are a professional PCI DSS Compliance Auditor. Analyze the attached document against this compliance requirement:\n\n\"{{ $json.requirement_text }}\"\n\nAnalyze the document carefully. Assess if the evidence is sufficient, partially sufficient, or completely lacking to meet the requirement. Write a formal audit observation and list actionable recommendations if there are gaps (or state 'None' if fully compliant).\n\nYou must return a JSON response matching the following structure:\n{\n  \"status\": \"completed\",\n  \"observations\": \"Detailed analysis and observations explaining what the file shows and why it is/is not compliant.\",\n  \"recommendations\": \"Actionable steps for remediation, or 'None' if fully compliant.\"\n}"
        }
      ]
    }
  ],
  "generationConfig": {
    "responseMimeType": "application/json"
  }
}

parameters.jsCode:
if ($json.error) {
  return {
    status: 'failed',
    observations: 'Gemini API Error: ' + ($json.error.message || JSON.stringify($json.error)),
    recommendations: 'Please check your API key and connection settings.'
  };
}
if ($json.candidates && $json.candidates[0]) {
  try {
    let responseText = $json.candidates[0].content.parts[0].text;
    responseText = responseText.replace(/```json/g, '').replace(/```/g, '').trim();
    const result = JSON.parse(responseText);

    let observations = result.observations || 'No observations generated by AI.';
    if (Array.isArray(observations)) {
      observations = observations.join('\n');
    } else if (typeof observations !== 'string') {
      observations = JSON.stringify(observations);
    }

    let recommendations = result.recommendations || 'None';
    if (Array.isArray(recommendations)) {
      recommendations = recommendations.join('\n');
    } else if (typeof recommendations !== 'string') {
      recommendations = JSON.stringify(recommendations);
    }

    return {
      status: 'completed',
      observations: observations,
      recommendations: recommendations
    };
  } catch (e) {
    return {
      status: 'failed',
      observations: 'Failed to parse Gemini response: ' + e.message,
      recommendations: 'Ensure the model output conforms to the JSON schema.'
    };
  }
}
return {
  status: 'failed',
  observations: 'AI Analysis Failed: No candidates returned from Gemini API.',
  recommendations: 'Verify the uploaded file format and content size.'
};
